import {sync,ModifierState} from "@hoge1e3/key-stream";
import {modifierState, KP_ModifierState, Datas,KP_ModifierStateValue, KP_ModifierKeys, mLock,modifierKeys,LockType} from "./types.js";

export function currentModifierState(){
    return modifierState;
}
// TODO: delete 
export function modifierStateToInt(s:KP_ModifierState){
    s=s||modifierState;
    return ssToInt(s);
}
export function modifierStateToKeyboardEvent(kps?:KP_ModifierState):ModifierState{
    const s=kps||modifierState;
    return {
        shiftKey:!!s.shift,
        ctrlKey:!!s.ctrl,
        altKey: false,
        metaKey: false,
    };
}
export function syncAsKeyboardEvent(s:KP_ModifierState){
  sync(modifierStateToKeyboardEvent(s));
}
export function setModifier(k:KP_ModifierKeys,v:KP_ModifierStateValue){
    switch(v){
        case 0:
            modifierState[k]=0;
            mLock[k]=0;
            break;
        case 1:
            modifierState[k]=1;
            mLock[k]=0;
            break;
        case 2:
            modifierState[k]=1;
            mLock[k]=1;
            break;
    }
}
export function getModifier(k:KP_ModifierKeys){
    return modifierState[k];
}
export function modifierLocked(k:KP_ModifierKeys){
    return mLock[k];
}
export function clearUnlockedModifiers(){
    for(let _k in modifierState){
        const k=_k as KP_ModifierKeys;
        if(modifierLocked(k))continue;
        modifierState[k]=0;
    }
}
// TODO: delete
export function ssToInt(e:any){
    return 0 | 
    (e.ctrl ? 1 : 0) | 
    (e.alt ? 2 : 0) | 
    (e.shift ? 4 : 0) | 
    (e.meta ? 8 : 0);
}
//------keypad 
// moved to keypad.js

export function modifierButtonPressed(d:Datas){
    let mod=d.modifier;
    if (!mod) return;
    let lock:LockType=d.lock||"double";
    if(!modifierState[mod]){
        modifierState[mod]=1;
        if(lock=="single"){
            mLock[mod]=1;
        }
    }else if(lock!="none"&&
    !mLock[mod]){
        mLock[mod]=1;
    }else{
        modifierState[mod]=
        mLock[mod]=0;
    }
    if(d["modifier-off"]){
        modifierState[d["modifier-off"]]=0;
    }
    return;
}
export function addModifierStyle(){
  const styleEl = document.createElement("style");
  styleEl.setAttribute("id","sutairu");
  // Append <style> element to <head>
  document.head.appendChild(styleEl);
  // Grab style element's sheet
  const styleSheet = styleEl.sheet!;
  //styleSheet.insertRule("button{color:blue;}");
  for(let k in modifierKeys){
    styleSheet.insertRule(`#keypad.${k} .mask.no-${k}{
        display: none;
    }`);
    styleSheet.insertRule(`#keypad:not(.${k}) .mask.${k}{
        display: none;
    }`);
  }
}
